create table if not exists public.profile_privacy_settings(user_id uuid primary key references public.profiles(id) on delete cascade,profile_visibility text not null default 'everyone' check(profile_visibility in('everyone','shared_communities','friends')),show_location boolean not null default true,show_timezone boolean not null default true,show_activity boolean not null default true,show_media boolean not null default true,location text check(location is null or char_length(location)<=120),timezone text check(timezone is null or char_length(timezone)<=80),updated_at timestamptz not null default now());
alter table public.profile_privacy_settings enable row level security;revoke all on public.profile_privacy_settings from public,anon,authenticated;grant select on public.profile_privacy_settings to authenticated;create policy "profile_privacy_owner_select" on public.profile_privacy_settings for select to authenticated using(user_id=auth.uid());
create or replace function public.get_own_profile_privacy() returns table(profile_visibility text,show_location boolean,show_timezone boolean,show_activity boolean,show_media boolean) language plpgsql security definer set search_path=public as $$begin insert into public.profile_privacy_settings(user_id) values(auth.uid()) on conflict do nothing;return query select settings.profile_visibility,settings.show_location,settings.show_timezone,settings.show_activity,settings.show_media from public.profile_privacy_settings settings where settings.user_id=auth.uid();end$$;
create or replace function public.update_profile_privacy(next_visibility text,next_show_location boolean,next_show_timezone boolean,next_show_activity boolean,next_show_media boolean) returns boolean language plpgsql security definer set search_path=public as $$begin if auth.uid() is null or next_visibility not in('everyone','shared_communities','friends') then raise exception 'PROFILE_PRIVACY_INVALID' using errcode='22023';end if;insert into public.profile_privacy_settings(user_id,profile_visibility,show_location,show_timezone,show_activity,show_media,updated_at) values(auth.uid(),next_visibility,next_show_location,next_show_timezone,next_show_activity,next_show_media,now()) on conflict(user_id) do update set profile_visibility=excluded.profile_visibility,show_location=excluded.show_location,show_timezone=excluded.show_timezone,show_activity=excluded.show_activity,show_media=excluded.show_media,updated_at=now();return true;end$$;
create or replace function public.get_profile_privacy_projection(target_user_id uuid) returns table(can_view_profile boolean,show_location boolean,show_timezone boolean,show_activity boolean,show_media boolean,location text,timezone text) language plpgsql stable security definer set search_path=public as $$declare settings public.profile_privacy_settings%rowtype;shared_access boolean;friend_access boolean;allowed boolean;begin select * into settings from public.profile_privacy_settings where user_id=target_user_id;if settings.user_id is null then settings.profile_visibility:='everyone';settings.show_location:=true;settings.show_timezone:=true;settings.show_activity:=true;settings.show_media:=true;end if;shared_access:=exists(select 1 from public.community_members viewer join public.community_members target on target.community_id=viewer.community_id where viewer.user_id=auth.uid() and target.user_id=target_user_id);friend_access:=public.are_friends(auth.uid(),target_user_id);allowed:=auth.uid()=target_user_id or (not public.users_are_blocked(auth.uid(),target_user_id) and (settings.profile_visibility='everyone' or (settings.profile_visibility='shared_communities' and shared_access) or (settings.profile_visibility='friends' and friend_access)));return query select allowed,allowed and settings.show_location,allowed and settings.show_timezone,allowed and settings.show_activity and (auth.uid()=target_user_id or shared_access or friend_access),allowed and settings.show_media and (auth.uid()=target_user_id or shared_access or friend_access),case when allowed and settings.show_location then settings.location end,case when allowed and settings.show_timezone then settings.timezone end;end$$;
create or replace function public.list_visible_profile_activity(target_user_id uuid,result_limit integer default 30) returns table(message_id uuid,community_id uuid,channel_id uuid,preview text,created_at timestamptz) language sql stable security definer set search_path=public as $$select message.id,channel.community_id,message.channel_id,left(message.body,240),message.created_at from public.messages message join public.channels channel on channel.id=message.channel_id where message.author_id=target_user_id and message.deleted_at is null and public.can_view_channel(message.channel_id) and exists(select 1 from public.get_profile_privacy_projection(target_user_id) projection where projection.show_activity) order by message.created_at desc limit least(greatest(result_limit,1),50);$$;
revoke all on function public.get_own_profile_privacy(),public.update_profile_privacy(text,boolean,boolean,boolean,boolean),public.get_profile_privacy_projection(uuid),public.list_visible_profile_activity(uuid,integer) from public,anon;
grant execute on function public.get_own_profile_privacy(),public.update_profile_privacy(text,boolean,boolean,boolean,boolean),public.get_profile_privacy_projection(uuid),public.list_visible_profile_activity(uuid,integer) to authenticated;
comment on table public.profile_privacy_settings is 'Owner-private preferences and optional location/timezone values. Activity visibility still requires per-channel authorization.';
